E = (B + reflect(C,A)*(B))/2;
F = (C + reflect(A,B)*(C))/2;
H = extension(B,E,C,F);

draw(B--H--C--cycle);
draw(H--D);
draw(B--F);
draw(C--E);

label("$A$", A, SE);
label("$B$", B, SW);
label("$C$", C, SE);
label("$D$", D, S);
label("$E$", E, W);
label("$F$", F, NE);
